// // (1) reset: Resets the counter to 5'b11111.
// (2) dir: Direction control (1 for down, 0 for up).
// (3) q: The value of the counter.
module top_module(
    input clk,
    input reset,
    input dir,
    output reg [4:0] q
);

    always @(posedge clk) begin
        if (reset) begin
            // Synchronous reset: Reset the counter to 5'b00000
            q <= 5'b00000;
        end else if (dir) begin
            // Up counter
            q <= q + 1;
        end else begin
            // Down counter
            q <= q - 1;
        end
    end

endmodule

